import { motion, AnimatePresence } from "framer-motion";
import { ChevronDown } from "lucide-react";
import { linkHomeDesign as design } from "../../../design/linkHomeDesign";

const LinkAdd = ({
  name,
  setName,
  isActive,
  setIsActive,
  statusOptions,
  statusDropdown,
  setStatusDropdown,
  statusRef,
  handleSubmit,
  setView,
  nameError,
  editId
}) => {
  return (
    <div className="flex justify-center mt-8">
      <div className="w-full max-w-xl">

        <AnimatePresence mode="wait">
          <motion.form
            key="add"
            initial={{ opacity: 0, x: 30 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -30 }}
            transition={{ duration: 0.3 }}
            onSubmit={handleSubmit}
            className="bg-white p-6 rounded-2xl border border-slate-200 shadow-lg space-y-4"
          >

            {/* Title */}
            <div className="text-center">
              <h2 className="text-xl font-semibold text-slate-800">
                {editId ? "Update Link" : "Add Link"}
              </h2>
            </div>

            {/* Input */}
            <input
              type="text"
              placeholder="Link Name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="border border-slate-200 rounded-xl px-4 h-10 text-sm outline-none focus:ring-2 focus:ring-slate-400 transition w-full"
              required
            />

            {nameError && (
              <p className="text-red-500 text-sm">
                {nameError}
              </p>
            )}

            {/* Status Dropdown */}
            <div className="relative w-full" ref={statusRef}>
              <button
                type="button"
                onClick={() =>
                  setStatusDropdown(!statusDropdown)
                }
                className="flex items-center justify-between gap-2 bg-white border border-slate-300 px-4 h-10 rounded-xl text-sm shadow-sm hover:shadow-md transition w-full"
              >
                {
                  statusOptions.find(
                    (o) => o.value === isActive
                  )?.label
                }
                <ChevronDown size={16} />
              </button>

              <AnimatePresence>
                {statusDropdown && (
                  <motion.div
                    initial={{ opacity: 0, y: -6 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0 }}
                    className="absolute left-0 mt-2 w-full bg-white border border-slate-200 rounded-xl shadow-xl overflow-hidden z-50"
                  >
                    {statusOptions.map((option) => (
                      <div
                        key={option.label}
                        onClick={() => {
                          setIsActive(option.value);
                          setStatusDropdown(false);
                        }}
                        className="px-4 py-2 text-sm hover:bg-slate-100 cursor-pointer transition"
                      >
                        {option.label}
                      </div>
                    ))}
                  </motion.div>
                )}
              </AnimatePresence>
            </div>

            {/* Buttons */}
            <div className="flex gap-4">
              <button
                type="submit"
                className="w-1/2 bg-gradient-to-r from-slate-600 to-slate-800 text-white px-5 py-2 rounded-xl text-sm font-medium shadow-md hover:shadow-xl transition-all"
              >
                {editId ? "Update" : "Create"}
              </button>

              <button
                type="button"
                onClick={() => setView("home")}
                className="w-1/2 bg-slate-200 hover:bg-slate-300 text-slate-700 px-5 py-2 rounded-xl text-sm transition"
              >
                Cancel
              </button>
            </div>

          </motion.form>
        </AnimatePresence>

      </div>
    </div>
  );
};

export default LinkAdd;
